export interface CustomJsContext {
  name: string;
  props: Record<string, unknown>;
}

export interface CustomJsMessageApi {
  [key: string]: ((content: string) => void) | unknown;
}

export interface RunCustomJsOptions {
  code: string;
  context: CustomJsContext;
  args: unknown[];
  message: CustomJsMessageApi;
}

export interface RunShowMessageOptions {
  message: CustomJsMessageApi;
  type?: string;
  text?: string;
}

export interface RunGoToLinkOptions {
  url?: string;
  target?: string;
}

export type RuntimeActionName = 'customJs' | 'goToLink' | 'showMessage';

export interface RuntimeActionPayloadMap {
  customJs: Omit<RunCustomJsOptions, 'message'>;
  goToLink: RunGoToLinkOptions;
  showMessage: Omit<RunShowMessageOptions, 'message'>;
}

export interface RuntimeActionContext {
  message: CustomJsMessageApi;
}

export function runShowMessage({
  message,
  type = 'info',
  text = '',
}: RunShowMessageOptions) {
  const messageType =
    typeof type === 'string' && typeof message[type] === 'function'
      ? type
      : 'info';
  const normalizedText = typeof text === 'string' ? text : String(text ?? '');
  const showMessage = message[messageType];

  if (typeof showMessage === 'function') {
    return showMessage(normalizedText);
  }

  return undefined;
}

export function runGoToLink({
  url,
  target = '_blank',
}: RunGoToLinkOptions) {
  if (!url) {
    return undefined;
  }

  return window.open(url, target, 'noopener,noreferrer');
}

export function runCustomJs({
  code,
  context,
  args,
  message,
}: RunCustomJsOptions) {
  try {
    const runner = new Function('ShowMessage', 'context', 'args', code);
    return runner(
      (content: unknown, type = 'success') =>
        runShowMessage({
          message,
          type,
          text: typeof content === 'string' ? content : String(content ?? ''),
        }),
      context,
      args
    );
  } catch (error) {
    const errorMessage =
      error instanceof Error ? error.message : String(error ?? 'Unknown error');
    console.error('[customJs] execute failed:', error);

    const showError = message.error;
    if (typeof showError === 'function') {
      showError(errorMessage);
    }

    return undefined;
  }
}

const actionRegistry: {
  [K in RuntimeActionName]: (
    payload: RuntimeActionPayloadMap[K],
    context: RuntimeActionContext
  ) => unknown;
} = {
  customJs: (payload, context) =>
    runCustomJs({
      ...payload,
      message: context.message,
    }),
  goToLink: (payload) => runGoToLink(payload),
  showMessage: (payload, context) =>
    runShowMessage({
      ...payload,
      message: context.message,
    }),
};

export function runAction<K extends RuntimeActionName>(
  actionName: K,
  payload: RuntimeActionPayloadMap[K],
  context: RuntimeActionContext
) {
  const executor = actionRegistry[actionName];

  if (!executor) {
    console.warn('[runtime] unknown action:', actionName);
    return undefined;
  }

  return executor(payload, context);
}
